      field.setAccessible(true);
      field.set(target, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Helper to mock private static method getRuntimeTypeIfMoreSpecific via reflection
  private static void setPrivateStaticMethodReturn(TypeAdapterRuntimeTypeWrapper<?> spyWrapper, String methodName, Type returnType, Object... args) {
    try {
      // getDeclaredMethod for static method
      java.lang.reflect.Method method = TypeAdapterRuntimeTypeWrapper.class.getDeclaredMethod(methodName, Type.class, Object.class);
      method.setAccessible(true);

