      // then mock that method in the spy.

      // This helper is a placeholder to show this approach.
      // The actual mocking is done by defining a helper method getRuntimeTypeIfMoreSpecificViaReflection in the spyWrapper subclass.
      // So no implementation here is needed.

    } catch (NoSuchMethodException e) {
      throw new RuntimeException(e);
    }
  }
}
